import { useEffect, useState } from "react";
import api from "../api/axios";

export default function Patient() {
  const [list, setList] = useState([]);

  useEffect(() => {
    api.get("/patients").then(res => setList(res.data));
  }, []);

  return (
    <div>
      <h3>Patients</h3>
      {list.map(p => <div key={p._id}>{p.name}</div>)}
    </div>
  );
}
